export type institutionDashboardResponse200 = {
  data: Blob;
  status: 200;
};

export type institutionDashboardResponseSuccess = institutionDashboardResponse200 & {
  headers: Headers;
};
export type institutionDashboardResponse = institutionDashboardResponseSuccess;

export const getInstitutionDashboardUrl = (
  trackerId: string,
  params?: InstitutionDashboardParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/institution/${trackerId}/dashboard?${stringifiedParams}`
    : `/api/institution/${trackerId}/dashboard`;
};

export const institutionDashboard = async (
  trackerId: string,
  params?: InstitutionDashboardParams,
  options?: RequestInit,
): Promise<institutionDashboardResponse> => {
  const res = await fetch(getInstitutionDashboardUrl(trackerId, params), {
    ...options,
    method: 'GET',
  });

  const body = [204, 205, 304].includes(res.status) ? null : await res.text();

  const data: institutionDashboardResponse['data'] = body ? JSON.parse(body) : {};
  return { data, status: res.status, headers: res.headers } as institutionDashboardResponse;
};

export const getInstitutionDashboardQueryKey = (
  trackerId: string,
  params?: InstitutionDashboardParams,
) => {
  return [`/api/institution/${trackerId}/dashboard`, ...(params ? [params] : [])] as const;
};

export const getInstitutionDashboardQueryOptions = <
  TData = Awaited<ReturnType<typeof institutionDashboard>>,
  TError = unknown,
>(
  trackerId: string,
  params?: InstitutionDashboardParams,
  options?: {
    query?: Partial<
      UseQueryOptions<Awaited<ReturnType<typeof institutionDashboard>>, TError, TData>
    >;
    fetch?: RequestInit;
  },
) => {
  const { query: queryOptions, fetch: fetchOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getInstitutionDashboardQueryKey(trackerId, params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof institutionDashboard>>> = ({ signal }) =>
    institutionDashboard(trackerId, params, { signal, ...fetchOptions });

  return { queryKey, queryFn, enabled: !!trackerId, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof institutionDashboard>>,
    TError,
    TData
  > & { queryKey: DataTag<QueryKey, TData, TError> };
};

